1	import { useCallback, useEffect, useMemo, useRef, useState } from "react";
2	import { useDawStore } from "@state/store";
3	import { SynthEditor } from "@ui/synth";
4	import { DrumMachinePanel } from "@ui/drum-machine";
5	import { useTrackAudioBridge } from "@audio/TrackAudioBridgeProvider";
6	import type { TrackAudioBridge } from "@audio/track-audio-bridge";
7	import { useTransport } from "@audio/use-transport";
8	import type {
9	  DrumInstrumentId,
10	  DrumInstrumentParams,
11	  DrumPattern,
12	} from "@audio/drum-machine/drum-types";
13	import {
14	  DRUM_INSTRUMENTS,
15	  DRUM_TO_PITCH,
16	} from "@audio/drum-machine/drum-types";
17	import type { MidiClipModel, MIDINoteEvent } from "@state/track/types";
18	import { AddClipCommand } from "@state/track/track-commands";
19	import { sharedUndoManager } from "@state/undo";
20	import {
21	  sequencerCache,
22	  paramsCache,
23	  getOrCreateSequencer,
24	  getOrCreateParams,
25	} from "@audio/drum-machine/sequencer-cache";
26	import styles from "./panels.module.css";
27	
28	// Re-export for test compatibility
29	export { sequencerCache, paramsCache };
30	
31	function useDrumMachineState(trackId: string): {
32	  pattern: DrumPattern;
33	  currentStep: number;
34	  params: Record<DrumInstrumentId, DrumInstrumentParams>;
35	  onToggleStep: (instrumentId: DrumInstrumentId, stepIndex: number) => void;
36	  onSetAccent: (stepIndex: number, accent: boolean) => void;
37	  onTriggerPad: (instrumentId: DrumInstrumentId) => void;
38	  onParamChange: (
39	    instrumentId: DrumInstrumentId,
40	    key: keyof DrumInstrumentParams,
41	    value: number,
42	  ) => void;
43	  onSwitchPattern: (name: string) => void;
44	  onClearPattern: () => void;
45	  onCommitToTimeline: () => void;
46	} {
47	  const transport = useTransport();
48	  const transportState = useDawStore((s) => s.transportState);
49	  const bpm = useDawStore((s) => s.bpm);
50	
51	  const seq = getOrCreateSequencer(trackId);
52	
53	  const [pattern, setPattern] = useState<DrumPattern>(() => seq.getPattern());
54	  const [liveStep, setLiveStep] = useState(0);
55	  const [params, setParams] = useState<
56	    Record<DrumInstrumentId, DrumInstrumentParams>
57	  >(() => getOrCreateParams(trackId));
58	
59	  // Sync pattern when trackId changes (sequencer instance changes)
60	  useEffect(() => {
61	    setPattern(seq.getPattern());
62	  }, [seq]);
63	
64	  // Transport sync: advance step indicator when playing
65	  const rafRef = useRef(0);
66	  useEffect(() => {
67	    if (transportState !== "playing") return;
68	
69	    const clock = transport.getClock();
70	    if (!clock) return;
71	
72	    const stepsPerBeat = 4; // 16th notes
73	    let lastStep = -1;
74	
75	    const tick = (): void => {
76	      const cursor = clock.getCursorSeconds();
77	      const stepDuration = 60 / (bpm * stepsPerBeat);
78	      const step = Math.floor(cursor / stepDuration) % pattern.steps.length;
79	      if (step !== lastStep) {
80	        lastStep = step;
81	        setLiveStep(step);
82	      }
83	      rafRef.current = requestAnimationFrame(tick);
84	    };
85	    rafRef.current = requestAnimationFrame(tick);
86	
87	    return () => {
88	      cancelAnimationFrame(rafRef.current);
89	    };
90	  }, [transportState, transport, bpm, pattern.steps.length]);
91	
92	  // Audio scheduling is handled persistently by DrumSchedulerService
93	  // in TrackAudioBridgeProvider (not here, so it survives track deselection).
94	
95	  // Derive currentStep: 0 when stopped, liveStep when playing/paused
96	  const currentStep = transportState === "stopped" ? 0 : liveStep;
97	
98	  const onToggleStep = useCallback(
99	    (instrumentId: DrumInstrumentId, stepIndex: number) => {
100	      seq.toggleStep(instrumentId, stepIndex);
101	      setPattern(seq.getPattern());
102	    },
103	    [seq],
104	  );
105	
106	  const onSetAccent = useCallback(
107	    (stepIndex: number, accent: boolean) => {
108	      seq.setAccent(stepIndex, accent);
109	      setPattern(seq.getPattern());
110	    },
111	    [seq],
112	  );
113	
114	  const bridge = useTrackAudioBridge();
115	  const onTriggerPad = useCallback(
116	    (instrumentId: DrumInstrumentId) => {
117	      const kit = bridge.getDrumKit(trackId);
118	      kit?.trigger(instrumentId, 0, 1);
119	    },
120	    [bridge, trackId],
121	  );
122	
123	  const onParamChange = useCallback(
124	    (
125	      instrumentId: DrumInstrumentId,
126	      key: keyof DrumInstrumentParams,
127	      value: number,
128	    ) => {
129	      // Forward to audio engine
130	      const kit = bridge.getDrumKit(trackId);
131	      kit?.setParam(instrumentId, key, value);
132	
133	      setParams((prev) => {
134	        const next = {
135	          ...prev,
136	          [instrumentId]: { ...prev[instrumentId], [key]: value },
137	        };
138	        paramsCache.set(trackId, next);
139	        return next;
140	      });
141	    },
142	    [bridge, trackId],
143	  );
144	
145	  const onSwitchPattern = useCallback(
146	    (name: string) => {
147	      seq.switchPattern(name);
148	      setPattern(seq.getPattern());
149	    },
150	    [seq],
151	  );
152	
153	  const onClearPattern = useCallback(() => {
154	    seq.clearPattern();
155	    setPattern(seq.getPattern());
156	  }, [seq]);
157	
158	  const onCommitToTimeline = useCallback(() => {
159	    const state = useDawStore.getState();
160	    const currentPattern = seq.getPattern();
161	    const barDuration = (60 / state.bpm) * 4; // 1 bar = 4 beats
162	    const stepDuration = barDuration / currentPattern.steps.length;
163	
164	    const noteEvents: MIDINoteEvent[] = [];
165	    for (let i = 0; i < currentPattern.steps.length; i++) {
166	      const step = currentPattern.steps[i];
167	      if (!step) continue;
168	      const velocity = step.accent ? 127 : 100;
169	      for (const { id: instId } of DRUM_INSTRUMENTS) {
170	        if (!step.triggers[instId]) continue;
171	        const pitch = DRUM_TO_PITCH[instId];
172	        noteEvents.push({
173	          id: "note-" + crypto.randomUUID(),
174	          pitch,
175	          velocity,
176	          startTime: i * stepDuration,
177	          duration: stepDuration * 0.8,
178	        });
179	      }
180	    }
181	
182	    if (noteEvents.length === 0) return;
183	
184	    const clip: MidiClipModel = {
185	      type: "midi",
186	      id: "clip-" + crypto.randomUUID(),
187	      trackId,
188	      startTime: state.cursorSeconds,
189	      duration: barDuration,
190	      noteEvents,
191	      name: "808 " + currentPattern.name,
192	    };
193	
194	    const cmd = new AddClipCommand(clip);
195	    cmd.execute();
196	    sharedUndoManager.push(cmd);
197	  }, [seq, trackId]);
198	
199	  return {
200	    pattern,
201	    currentStep,
202	    params,
203	    onToggleStep,
204	    onSetAccent,
205	    onTriggerPad,
206	    onParamChange,
207	    onSwitchPattern,
208	    onClearPattern,
209	    onCommitToTimeline,
210	  };
211	}
212	
213	function DrumMachineController({
214	  trackId,
215	}: {
216	  trackId: string;
217	}): React.JSX.Element {
218	  const state = useDrumMachineState(trackId);
219	  return (
220	    <DrumMachinePanel
221	      pattern={state.pattern}
222	      currentStep={state.currentStep}
223	      activePatternName={state.pattern.name}
224	      onToggleStep={state.onToggleStep}
225	      onSetAccent={state.onSetAccent}
226	      onTriggerPad={state.onTriggerPad}
227	      onParamChange={state.onParamChange}
228	      onSwitchPattern={state.onSwitchPattern}
229	      onClearPattern={state.onClearPattern}
230	      onCommitToTimeline={state.onCommitToTimeline}
231	      params={state.params}
232	    />
233	  );
234	}
235	
236	function SynthTrackPanel({
237	  trackId,
238	  bridge,
239	}: {
240	  trackId: string;
241	  bridge: TrackAudioBridge;
242	}): React.JSX.Element {
243	  const instrument = bridge.getInstrument(trackId);
244	  const onNoteOn = useMemo(
245	    () =>
246	      instrument
247	        ? (note: number, velocity: number) => {
248	            instrument.noteOn(note, velocity);
249	          }
250	        : undefined,
251	    [instrument],
252	  );
253	  const onNoteOff = useMemo(
254	    () =>
255	      instrument
256	        ? (note: number) => {
257	            instrument.noteOff(note);
258	          }
259	        : undefined,
260	    [instrument],
261	  );
262	  return (
263	    <section
264	      data-testid="instrument-panel"
265	      className={styles["instrumentPanelFull"]}
266	    >
267	      <SynthEditor
268	        trackId={trackId}
269	        onNoteOn={onNoteOn}
270	        onNoteOff={onNoteOff}
271	      />
272	    </section>
273	  );
274	}
275	
276	export function InstrumentPanel(): React.JSX.Element {
277	  const selectedTrackIds = useDawStore((s) => s.selectedTrackIds);
278	  const tracks = useDawStore((s) => s.tracks);
279	  const selectedTrack = tracks.find((t) => selectedTrackIds.includes(t.id));
280	  const bridge = useTrackAudioBridge();
281	
282	  if (selectedTrack?.type === "instrument") {
283	    return <SynthTrackPanel trackId={selectedTrack.id} bridge={bridge} />;
284	  }
