27	  exponentialRampToValueAtTime: ReturnType<typeof vi.fn>;
28	  cancelScheduledValues: ReturnType<typeof vi.fn>;
29	};
30	
31	function createMockParam(initial = 0): MockAudioParam {
32	  const param: MockAudioParam = {
33	    value: initial,
34	    setValueAtTime: vi.fn(),
35	    linearRampToValueAtTime: vi.fn(),
36	    exponentialRampToValueAtTime: vi.fn(),
37	    cancelScheduledValues: vi.fn(),
38	  };
39	  // Wire up value tracking
40	  param.setValueAtTime.mockImplementation((v: number) => {
41	    param.value = v;
42	  });
43	  param.linearRampToValueAtTime.mockImplementation((v: number) => {
44	    param.value = v;
45	  });
46	  param.exponentialRampToValueAtTime.mockImplementation((v: number) => {
47	    if (v <= 0) throw new DOMException("value must be positive", "RangeError");
48	    param.value = v;
49	  });
50	  return param;
51	}
